module.exports = "<!--Basic Badges Starts-->\r\n<section id=\"basic-badges\">\r\n    <div class=\"row text-left\">\r\n        <div class=\"col-sm-12\">\r\n            <div class=\"content-header\">مدال ها</div>\r\n        </div>\r\n    </div>\r\n    <div class=\"row text-left\" matchHeight =\"card\">\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان اولیه</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر اولیه، رنگی استفاده کنید<code>.badge-primary</code>.</p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-primary\">اولیه</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانگر ثانویه</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر ثانویه، رنگی استفاده کنید <code>.badge-secondary</code> </p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-secondary\">ثانویه</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانه موفقیت</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر موفقیت، رنگی استفاده کنید <code>.badge-success</code> </p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-success\">موفقیت</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان خطر</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر خطر، رنگی استفاده کنید <code>.badge-danger</code> </p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-danger\">خطر</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان اطلاعات</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر اطلاعات ، رنگی استفاده کنید <code>.badge-info</code> </p>\r\n\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-info\">اطلاعات</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان هشدار</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر هشدار، رنگی استفاده کنید <code>.badge-warning</code> </p>\r\n\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-warning\">هشدار</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانه نور</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر نور، رنگی استفاده کنید <code>.badge-light</code> </p>\r\n\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-light\">نور</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان تیره</h4>\r\n                    <p>استفاده از کلاس <code>.badge</code> برای گرفتن مدرک برای استفاده از نشانگر تیره، رنگی استفاده کنید <code>.badge-dark</code> </p>\r\n\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-dark\">تیره</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n<!--Basic Badges Starts-->\r\n\r\n<!--Badge With Components Starts-->\r\n<section id=\"component-badges\">\r\n    <div class=\"row text-left\">\r\n        <div class=\"col-sm-12\">\r\n            <div class=\"content-header\">نشان با اجزاء</div>\r\n            <p class=\"content-sub-header\">به راحتی موارد جدید و یا خوانده نشده را با اضافه کردن یک مورد برجسته کنید\r\n                    <code>&lt;span class=\"badge\"&gt;</code> به لینک ها، ناوبری بوت استرپ، و بیشتر. </p>\r\n        </div>\r\n    </div>\r\n    <div class=\"row text-left\" matchHeight =\"card\">\r\n        <div class=\"col-12 col-sm-6 col-md-6 col-lg-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان با لینک </h4>\r\n                    <p>استفاده از برچسب نشان در تگ لنگر برای نشان با لینک.</p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <a>ورودی <span class=\"badge badge-secondary\">42</span></a>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-6 col-lg-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان با دکمه</h4>\r\n                    <p>با استفاده از دکمه در برچسب دکمه برای نشان با استفاده از نشانگر استفاده کنید.</p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <button class=\"btn btn-danger btn-raised\" type=\"button\">\r\n                            پیام <span class=\"badge badge-light\">4</span>\r\n                        </button>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-md-12 col-lg-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">سازگار با وضعیت های فعال </h4>\r\n                    <p>سبک های ساخته شده برای قرار دادن مدالها در حالت فعال در navigations قرص گنجانده شده است. </p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <ul class=\"nav nav-pills\" role=\"tablist\">\r\n                            <li role=\"presentation\" class=\"nav-item\"><a class=\"nav-link active\">صفحه اصلی <span class=\"badge badge-success\">42</span></a></li>\r\n                            <li role=\"presentation\" class=\"nav-item\"><a class=\"nav-link\">پروفایل</a></li>\r\n                            <li role=\"presentation\" class=\"nav-item\"><a class=\"nav-link\">پیام <span class=\"badge badge-warning\">3</span></a></li>\r\n                        </ul>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n<!--Badge With Components Starts-->\r\n\r\n<!--Pill Badges Starts-->\r\n<section id=\"pill-badges\">\r\n    <div class=\"row text-left\">\r\n        <div class=\"col-sm-12\">\r\n            <div class=\"content-header\">نشان قرص</div>\r\n        </div>\r\n    </div>\r\n    <div class=\"row text-left\" matchHeight =\"card\">\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان اولیه</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر اولیه، رنگی استفاده کنید<code>.badge-primary</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-primary\">25</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانگر ثانویه</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر ثانویه، رنگی استفاده کنید<code>.badge-secondary</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-secondary\">85</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانه موفقیت</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر موفقیت، رنگی استفاده کنید<code>.badge-success</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-success\">41</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان خطر</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر خطر، رنگی استفاده کنید<code>.badge-danger</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-danger\">36</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان اطلاعات</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر اطلاعات، رنگی استفاده کنید<code>.badge-info</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-info\">77</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان هشدار</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر هشدار، رنگی استفاده کنید<code>.badge-warning</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-warning\">30</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشانه نور</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر روشن، رنگی استفاده کنید<code>.badge-light</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-light\">45</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <div class=\"col-12 col-sm-6 col-md-4\">\r\n            <div class=\"card\">\r\n                <div class=\"card-header\">\r\n                    <h4 class=\"card-title\">نشان تیره</h4>\r\n                    <p>استفاده از کلاس <code>.badge-pill</code> برای گرفتن قرص علامت دار برای استفاده از نشانگر تیره، رنگی استفاده کنید<code>.badge-dark</code></p>\r\n                </div>\r\n                <div class=\"card-content\">\r\n                    <div class=\"card-body text-center\">\r\n                        <span class=\"badge badge-pill badge-dark\">37</span>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</section>\r\n<!--Pill Badges Starts-->"

