module.exports = "<section id=\"datepicker\">\r\n  <div class=\"row text-left\">\r\n    <div class=\"col-sm-12\">\r\n      <div class=\"content-header\">تقویم</div>\r\n    </div>\r\n  </div>\r\n  <div class=\"row text-left\" matchHeight=\"card\">\r\n    <!--Simple datepicker starts-->\r\n    <div class=\"col-md-12 col-lg-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">تقویم ساده</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-datepicker #dp [(ngModel)]=\"model\" (navigate)=\"date = $event.next\"></ngb-datepicker>\r\n\r\n            <div class=\"block mt-3 mb-3\">\r\n              <button class=\"btn btn-sm btn-outline-primary mr-1\" (click)=\"dp.navigateTo({year: 2013, month: 2})\">تا خرداد 1399</button>\r\n              <button class=\"btn btn-sm btn-outline-primary mr-1\" (click)=\"dp.navigateTo()\">ماه گذشته </button>\r\n              <button class=\"btn btn-sm btn-outline-primary\" (click)=\"selectToday()\">امروز انتخاب کنید</button>\r\n            </div>\r\n\r\n            <p>Month: {{ date.month }}.{{ date.year }}</p>\r\n            <p>Model: {{ model | json }}</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Simple datepicker Ends-->\r\n\r\n    <!--Disabled/Enabled datepicker starts-->\r\n    <div class=\"col-md-12 col-lg-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">تقویم غیرفعال</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-datepicker [(ngModel)]=\"disabledModel\" [disabled]=\"disabled\"></ngb-datepicker>\r\n\r\n            <div class=\"block mt-3\">\r\n              <button class=\"btn btn-sm btn-outline-{{disabled ? 'danger' : 'success'}}\" (click)=\"disabled = !disabled\">\r\n                {{ disabled ? \"disabled\" : \"enabled\"}}\r\n              </button>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Disabled/Enabled datepicker ends-->\r\n  </div>\r\n  <div class=\"row text-left\" matchHeight=\"card\">\r\n    <!--Datepicker in a popup starts-->\r\n    <div class=\"col-md-12 col-lg-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">تقویم در popup</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <form class=\"form-inline\">\r\n              <div class=\"form-group\">\r\n                <div class=\"input-group\">\r\n                  <input class=\"form-control\" placeholder=\"yyyy-mm-dd\" name=\"dp\" [(ngModel)]=\"popupModel\" ngbDatepicker\r\n                    #d2=\"ngbDatepicker\">\r\n                  <div class=\"input-group-append\">\r\n                    <div class=\"input-group-text\" (click)=\"d2.toggle()\">\r\n                      <i class=\"fa fa-calendar\" style=\"cursor: pointer;\"></i>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </form>\r\n            <p class=\"mt-4\">Model: {{ popupModel | json }}</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Datepicker in a popup ends-->\r\n\r\n    <!--Custom day view starts-->\r\n    <div class=\"col-md-12 col-lg-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">نمایش روزانه سفارشی </h4>\r\n          <p>\r\n              این تقویم از یک قالب سفارشی برای نمایش روزها استفاده می کند. تمام پایان هفته با یک پس زمینه نارنجی نمایش داده می شود.\r\n\r\n          </p>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <form class=\"form-inline\">\r\n              <div class=\"form-group\">\r\n                <div class=\"input-group\">\r\n                  <input class=\"form-control\" placeholder=\"yyyy-mm-dd\" name=\"dp\" [(ngModel)]=\"model\" ngbDatepicker\r\n                    [dayTemplate]=\"customDay\" [markDisabled]=\"isDisabled\" #d3=\"ngbDatepicker\">\r\n                  <div class=\"input-group-append\">\r\n                    <div class=\"input-group-text\" (click)=\"d3.toggle()\">\r\n                      <i class=\"fa fa-calendar\" style=\"cursor: pointer;\"></i>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </form>\r\n\r\n            <ng-template #customDay let-date=\"date\" let-currentMonth=\"currentMonth\" let-selected=\"selected\"\r\n              let-disabled=\"disabled\">\r\n              <span class=\"custom-day\" [class.weekend]=\"isWeekend(date)\" [class.bg-primary]=\"selected\" [class.hidden]=\"date.month !== currentMonth\"\r\n                [class.text-muted]=\"disabled\">\r\n                {{ date.day }}\r\n              </span>\r\n            </ng-template>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Custom day view ends-->\r\n  </div>\r\n  <div class=\"row text-left\" matchHeight=\"card\">\r\n    <!--Multiple months datepickers starts-->\r\n    <div class=\"col-lg-12 col-xl-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">چند ماه</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-datepicker [displayMonths]=\"displayMonths\" [navigation]=\"navigation\"></ngb-datepicker>\r\n\r\n            <p class=\"pt-3\">Inline</p>\r\n\r\n            <form class=\"form-inline\">\r\n              <div class=\"form-group\">\r\n                <div class=\"input-group\">\r\n                  <input class=\"form-control\" placeholder=\"yyyy-mm-dd\" name=\"dp\" [displayMonths]=\"displayMonths\"\r\n                    [navigation]=\"navigation\" ngbDatepicker #d=\"ngbDatepicker\">\r\n                  <div class=\"input-group-append\">\r\n                    <div class=\"input-group-text\" (click)=\"d.toggle()\">\r\n                      <i class=\"fa fa-calendar\" style=\"cursor: pointer;\"></i>\r\n                    </div>\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </form>\r\n\r\n            <p class=\"pt-3\">ویژگی</p>\r\n\r\n            <select class=\"custom-select\" [(ngModel)]=\"displayMonths\">\r\n              <option class=\"text-dark\" [ngValue]=\"1\">یک ماه</option>\r\n              <option class=\"text-dark\" [ngValue]=\"2\">دو ماه</option>\r\n            </select>\r\n\r\n            <select class=\"custom-select mt-1\" [(ngModel)]=\"navigation\">\r\n              <option class=\"text-dark\" value=\"none\">بدون ناوبری</option>\r\n              <option class=\"text-dark\" value=\"select\">با جعبه های انتخاب شده </option>\r\n              <option class=\"text-dark\" value=\"arrows\">بدون جعبه های انتخاب شده </option>\r\n            </select>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Multiple months datepickers ends-->\r\n\r\n    <!--Range selection datepickers starts-->\r\n    <div class=\"col-lg-12 col-xl-6\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">انتخاب محدوده</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-datepicker #dp1 ngModel (ngModelChange)=\"onDateChange($event)\" [displayMonths]=\"2\" [dayTemplate]=\"t\">\r\n            </ngb-datepicker>\r\n\r\n            <ng-template #t let-date=\"date\" let-focused=\"focused\">\r\n              <span class=\"custom-day\" [class.focused]=\"focused\" [class.range]=\"isFrom(date) || isTo(date) || isInside(date) || isHovered(date)\"\r\n                [class.faded]=\"isHovered(date) || isInside(date)\" (mouseenter)=\"hoveredDate = date\" (mouseleave)=\"hoveredDate = null\">\r\n                {{ date.day }}\r\n              </span>\r\n            </ng-template>\r\n\r\n            <hr>\r\n            <div class=\"row\">\r\n              <div class=\"col-12 col-md-6\">\r\n                <p>From: {{ fromDate | json }} </p>\r\n              </div>\r\n              <div class=\"col-12 col-md-6\">\r\n                <p>To: {{ toDate | json }} </p>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Range selection datepickers ends-->\r\n  </div>\r\n</section>\r\n"

