module.exports = "<!--Modal starts-->\r\n<section id=\"modals\">\r\n  <div class=\"row text-left\">\r\n    <div class=\"col-sm-12\">\r\n      <div class=\"content-header\">مودال ها</div>\r\n    </div>\r\n  </div>\r\n  <div class=\"row text-left\" matchHeight=\"card\">\r\n    <!--Modal with Default options starts-->\r\n    <div class=\"col-sm-12 col-md-6 col-lg-4\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">مودال با گزینه های پیش فرض</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ng-template #content let-c=\"close\" let-d=\"dismiss\">\r\n              <div class=\"modal-header\">\r\n                <h4 class=\"modal-title\">عنوان مودال</h4>\r\n                <button type=\"button\" class=\"close\" aria-label=\"Close\" (click)=\"d('Cross click')\">\r\n                  <span aria-hidden=\"true\">&times;</span>\r\n                </button>\r\n              </div>\r\n              <div class=\"modal-body\">\r\n                <p>بدنه ی مودال</p>\r\n              </div>\r\n              <div class=\"modal-footer\">\r\n                <button type=\"button\" class=\"btn btn-secondary btn-raised\" (click)=\"c('Close click')\">بستن</button>\r\n              </div>\r\n            </ng-template>\r\n\r\n            <button class=\"btn btn-lg btn-outline-primary\" (click)=\"open(content)\">راه اندازی نسخه آزمایشی</button>\r\n\r\n            <hr>\r\n            <p>عمل : {{closeResult}}</p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Modal with Default options ends-->\r\n\r\n    <!--Components as content starts-->\r\n    <div class=\"col-sm-12 col-md-6 col-lg-4\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">قطعات به عنوان محتوا</h4>\r\n          <p>شما می توانید یک جزء موجود را به عنوان محتوای پنجره مدال منتقل کنید. در این مورد به یاد داشته باشید که بخش محتوا را به عنوان بخش\r\n             <code>entryComponents</code> خود اضافه کنید. <code>NgModule</code>.</p>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <button class=\"btn btn-lg btn-outline-primary\" (click)=\"openContent()\">راه اندازی نسخه آزمایشی</button>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Components as content ends-->\r\n\r\n    <!--Modal with custom class starts-->\r\n    <div class=\"col-sm-12 col-md-6 col-lg-4\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">مدال با کلاس سفارشی</h4>\r\n          <p>با برخی سبک مدرن تاریک. </p>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ng-template #customContent let-c=\"close\" let-d=\"dismiss\">\r\n              <div class=\"modal-header\">\r\n                <h4 class=\"modal-title\">عنوان مودال</h4>\r\n                <button type=\"button\" class=\"close\" aria-label=\"Close\" (click)=\"d('Cross click')\">\r\n                  <span aria-hidden=\"true\">&times;</span>\r\n                </button>\r\n              </div>\r\n              <div class=\"modal-body\">\r\n                <p>اینجا مرا پیدا کن</p>\r\n              </div>\r\n              <div class=\"modal-footer\">\r\n                <button type=\"button\" class=\"btn btn-secondary btn-raised\" (click)=\"c('Close click')\">بستن</button>\r\n              </div>\r\n            </ng-template>\r\n            <button class=\"btn btn-lg btn-outline-primary\" (click)=\"openModal(customContent)\">راه اندازی نسخه آزمایشی</button>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Modal with custom class ends-->\r\n  </div>\r\n</section>\r\n<!--Modal ends-->\r\n"

