module.exports = "<!--Tabs Starts-->\r\n<section id=\"tabs\">\r\n  <div class=\"row text-left\">\r\n    <div class=\"col-sm-12\">\r\n      <div class=\"content-header\">تب ها</div>\r\n    </div>\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Tabset Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">تب</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset>\r\n              <ngb-tab title=\"Simple\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab>\r\n                <ng-template ngbTabTitle><b>تصادفی</b> عنوان</ng-template>\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab title=\"Disabled\" [disabled]=\"true\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Tabset Ends-->\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Pills Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">قرص</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset type=\"pills\">\r\n              <ngb-tab title=\"Simple\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab>\r\n                <ng-template ngbTabTitle><b>تصادفی</b> عنوان</ng-template>\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab title=\"Disabled\" [disabled]=\"true\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Pills Ends-->\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Select an active tab by id Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">Select an active tab by id</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset #t=\"ngbTabset\">\r\n              <ngb-tab title=\"Simple\" id=\"foo\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab id=\"bar\">\r\n                <ng-template ngbTabTitle><b>تصادفی</b> عنوان</ng-template>\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n            <p>\r\n              <button class=\"btn btn-outline-primary\" (click)=\"t.select('bar')\">برگه انتخاب شده با شناسه \"bar\"</button>\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Select an active tab by id Ends-->\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Prevent tab change Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">جلوگیری از تغییر زبانه </h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset (tabChange)=\"beforeChange($event)\">\r\n              <ngb-tab title=\"Simple\" id=\"foo\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab id=\"bar\" title=\"من نمی توانم... \">\r\n                <ng-template ngbTabContent>\r\n                  <p>من نمی توانم محتوا را انتخاب کنم</p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab title=\"But I can!\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Prevent tab change Ends-->\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Nav justification Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">توجیه ناپذیر </h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset [justify]=\"currentJustify\">\r\n              <ngb-tab title=\"Simple\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد .\r\n\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab>\r\n                <ng-template ngbTabTitle><b>تصادفی</b> عنوان</ng-template>\r\n                <ng-template ngbTabContent>\r\n                  <p> لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است.\r\n                    چاپگرها و\r\n                    متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab title=\"A very long nav title\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n\r\n            <div class=\"btn-group btn-group-toggle\" ngbRadioGroup [(ngModel)]=\"currentJustify\">\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"start\">شروع\r\n              </label>\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"center\">وسط\r\n              </label>\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"end\">پایان\r\n              </label>\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"fill\">پر کنید\r\n              </label>\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"justified\">تعدیل شده\r\n              </label>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Nav justification Ends-->\r\n  </div>\r\n  <div class=\"row text-left\">\r\n    <!--Nav orientation Starts-->\r\n    <div class=\"col-md-12 col-lg-12\">\r\n      <div class=\"card\">\r\n        <div class=\"card-header\">\r\n          <h4 class=\"card-title\">جهت گیری نوری</h4>\r\n        </div>\r\n        <div class=\"card-content\">\r\n          <div class=\"card-body\">\r\n            <ngb-tabset type=\"pills\" [orientation]=\"currentOrientation\">\r\n              <ngb-tab title=\"Simple\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab>\r\n                <ng-template ngbTabTitle><b>تصادفی</b> عنوان</ng-template>\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                  لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها و\r\n                  متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                  کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n              <ngb-tab title=\"Disabled\" [disabled]=\"true\">\r\n                <ng-template ngbTabContent>\r\n                  <p>\r\n                    لورم ایپسوم متن ساختگی با تولید سادگی نامفهوم از صنعت چاپ و با استفاده از طراحان گرافیک است. چاپگرها\r\n                    و متون بلکه روزنامه و مجله در ستون و سطرآنچنان که لازم است و برای شرایط فعلی تکنولوژی مورد نیاز و\r\n                    کاربردهای متنوع با هدف بهبود ابزارهای کاربردی می باشد.\r\n                  </p>\r\n                </ng-template>\r\n              </ngb-tab>\r\n            </ngb-tabset>\r\n\r\n            <div class=\"btn-group btn-group-toggle\" ngbRadioGroup [(ngModel)]=\"currentOrientation\">\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"horizontal\">افقی\r\n              </label>\r\n              <label ngbButtonLabel class=\"btn-outline-primary btn-sm\">\r\n                <input ngbButton type=\"radio\" value=\"vertical\">عمودی\r\n              </label>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <!--Nav orientation Ends-->\r\n  </div>\r\n</section>\r\n<!--Tabs Starts-->"

